# ║─Функции и методы: detect_jumps───────────────────────────────────────────────────────────────────║
# ║────────────────────────────────────────────────────────────────────────────────────────────────────║
def detect_jumps(occupancy_rates, jump_threshold):#───────────────────────────────────────────────────║
    """#──────────────────────────────────────────────────────────────────────────────────────────────║
    Detects significant jumps in occupancy rates between adjacent thresholds.#────────────────────────║
    """#──────────────────────────────────────────────────────────────────────────────────────────────║
    if occupancy_rates.ndim != 2 or occupancy_rates.shape[0] < 2:#────────────────────────────────────║
        return torch.zeros(0), torch.zeros(0)#────────────────────────────────────────────────────────║
#─────────────────────────────────────────────────────────────────────────────────────────────────────║
    jumps = []#───────────────────────────────────────────────────────────────────────────────────────║
    for i in range(occupancy_rates.shape[0] - 1):#────────────────────────────────────────────────────║
        diff = torch.abs(occupancy_rates[i+1] - occupancy_rates[i])#──────────────────────────────────║
        if diff > jump_threshold:#────────────────────────────────────────────────────────────────────║
            jumps.append(diff.item())#────────────────────────────────────────────────────────────────║
            #─────────────────────────────────────────────────────────────────────────────────────────║
    return torch.tensor(jumps), torch.zeros(len(jumps))#──────────────────────────────────────────────║
